/* NOTE: Like GetBestLengths and GetCostModelMinCost, this function takes a
   function-pointer parameter (costmodel).  Under the legacy `--enforce-contract`
   flow used by the scoring harness, CBMC 6.9.0 aborts at the *cbmc* step with an
   invariant violation ("__CPROVER__start::costmodel$object was not found") in the
   "Removal of function pointers and virtual functions" pass while removing the
   function pointer from the generated `__CPROVER__start` wrapper.  The abort is
   structural -- it happens for ANY function-pointer parameter regardless of the
   contract or body -- so this function cannot be verified by the harness.
   Confirmed empirically via tools.run_cbmc: goto-cc / replace-call-with-contract /
   enforce-contract all return 0; only cbmc aborts (rc 134).  All 6 mutants are
   therefore uncheckable (the unmutated original already crashes, so every mutant
   scores identically); the kill score is 0 and unimprovable without dfcc /
   `__CPROVER_obeys_contract`, which the fixed harness does not use.

   The contract below is the strongest SOUND statement expressible: costmodel must
   be a valid (non-NULL) pointer and instart <= inend (both forwarded to and
   required by GetBestLengths), the hash handle must be non-NULL, and on the trivial
   instart == inend path GetBestLengths returns 0, TraceBackwards/FollowPath are
   empty, and the run's cost is exactly 0.  No `assigns`/`frees` clause is given:
   the function frees *path and writes length_array, costs, *store and the hash
   through its callees, so any partial frame would be an unsound (false) framing
   claim -- omitting it makes no such claim. */
static double LZ77OptimalRun(ZopfliBlockState *s,
                             const unsigned char *in, size_t instart, size_t inend,
                             unsigned short **path, size_t *pathsize,
                             unsigned short *length_array, CostModelFun *costmodel,
                             void *costcontext, ZopfliLZ77Store *store,
                             ZopfliHash *h, float *costs)
__CPROVER_requires(costmodel != NULL)
__CPROVER_requires(instart <= inend)
__CPROVER_requires(h != NULL)
__CPROVER_ensures(instart == inend ==> __CPROVER_return_value == 0)
{
    double cost = GetBestLengths(s, in, instart, inend, costmodel,
                                 costcontext, length_array, h, costs);
    free(*path);
    *path = 0;
    *pathsize = 0;
    TraceBackwards(inend - instart, length_array, path, pathsize);
    FollowPath(s, in, instart, inend, *path, *pathsize, store, h);
    assert(cost < ZOPFLI_LARGE_FLOAT);
    return cost;
}

